const inputItems = $input.all();

let conditions = [];

if (inputItems.length > 1) {
  conditions = inputItems.map((item) => item.json).filter(Boolean);
} else {
  const payload = inputItems[0]?.json;
  if (Array.isArray(payload)) {
    conditions = payload;
  } else if (Array.isArray(payload?.data)) {
    conditions = payload.data;
  } else if (payload && typeof payload === 'object' && payload.id !== undefined) {
    conditions = [payload];
  }
}

if (conditions.length === 0) {
  return [{ json: { text: '조건식 목록이 비어 있습니다.' } }];
}

const normalizeStocks = (data) => {
  if (Array.isArray(data)) return data;
  if (Array.isArray(data?.data)) return data.data;
  if (Array.isArray(data?.stocks)) return data.stocks;
  if (Array.isArray(data?.items)) return data.items;
  if (Array.isArray(data?.results)) return data.results;
  return [];
};

const getRate = (stock) => {
  const raw = stock.change_rate ?? stock.rate ?? stock.fluctuation_rate ?? stock.percent_change ?? stock.changePercent;
  const num = Number(raw);
  if (!Number.isFinite(num)) return 'N/A';
  const sign = num > 0 ? '+' : '';
  return `${sign}${num.toFixed(2)}%`;
};

const getVolumeInMillions = (stock) => {
  const raw = stock.volume ?? stock.trade_volume ?? stock.acc_volume ?? stock.trading_volume;
  const num = Number(raw);
  if (!Number.isFinite(num)) return 'N/A';
  return `${(num / 1000000).toFixed(1)}M`;
};

const rawBase = $env.CONDITIONS_API_URL || 'http://144.24.81.83:8001/conditions/';
const baseOrigin = rawBase.replace(/\/conditions\/?$/i, '').replace(/\/$/, '');

const conditionBlocks = [];

for (let i = 0; i < conditions.length; i++) {
  const condition = conditions[i];
  const id = condition.id ?? condition.condition_id ?? '-';
  const apiId = condition.api_id ?? condition.apiId ?? condition.condition_api_id;
  const name = condition.name ?? condition.condition_name ?? '이름없음';
  const enabled = condition.enabled ?? condition.is_enabled ?? condition.is_active;
  const status = enabled === undefined ? 'UNKNOWN' : (enabled ? 'ON' : 'OFF');

  let stocks = [];
  let queryError = '';

  const candidateIds = [];
  if (id !== '-') candidateIds.push(id);
  if (apiId !== undefined && apiId !== null && apiId !== '' && apiId !== id) candidateIds.push(apiId);

  for (const cid of candidateIds) {
    try {
      const url = `${baseOrigin}/conditions/${cid}/stocks`;
      const data = await this.helpers.httpRequest({ method: 'GET', url, json: true });
      stocks = normalizeStocks(data);
      if (stocks.length > 0) break;
    } catch (error) {
      queryError = error.message;
    }
  }

  const stockText = stocks.length === 0
    ? `  - (해당 종목 없음${queryError ? ` / ${queryError}` : ''})`
    : stocks.slice(0, 20).map((s) => {
        const stockName = s.stock_name ?? s.name ?? s.stockName ?? '이름없음';
        const rate = getRate(s);
        const volume = getVolumeInMillions(s);
        return `  - ${stockName} | ${rate} | ${volume}`;
      }).join('\n');

  const moreText = stocks.length > 20 ? `\n  - ... 외 ${stocks.length - 20}개` : '';

  conditionBlocks.push(`${i + 1}. [${id}] ${name} (${status})\n${stockText}${moreText}`);
}

const now = new Date().toLocaleString('ko-KR', { timeZone: 'Asia/Seoul' });
const text = `조건식 + 종목 목록 (${conditions.length}개 조건식)\n기준시각: ${now}\n\n${conditionBlocks.join('\n\n')}`;

return [{ json: { text } }];
